## 2. C/C++ stub – **`pcapng_stubs.cpp`**

> **Important** – this file must be compiled as **C++** (e.g. `g++ -c …`) because
> it includes the C++ header of `libpcapng`.  The functions are exported with
> `extern "C"` so that the OCaml runtime can find them.

```cpp
/*--------------------------------------------------------------------
   pcapng_stubs.cpp – C++ glue for OCaml bindings to libpcapng
  --------------------------------------------------------------------*/

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <string>
#include <exception>
#include <stdexcept>
#include <cstdint>

/* ------------------------------------------------------------------
   The (fictional) C++ libpcapng API we are binding to.
   Replace the following #include and namespace with the real ones.
   ------------------------------------------------------------------ */
#include <pcapng.hpp>          // <-- real libpcapng header
using namespace pcapng;       // <-- real namespace

/* ------------------------------------------------------------------
   Helper: raise the OCaml exception [Error] defined in the .mli.
   ------------------------------------------------------------------ */
static void raise_error(const std::string& msg)
{
    caml_raise_with_string(*caml_named_value("Pcapng_error"), msg.c_str());
}

/* ------------------------------------------------------------------
   Custom block layout for the abstract type `t`.
   ------------------------------------------------------------------ */
struct caml_pcapng_handle {
    Capture* cap;      // libpcapng object (owns the file & iterator)
    bool    closed;    // true after an explicit close
    caml_pcapng_handle() : cap(nullptr), closed(false) {}
};

/* ------------------------------------------------------------------
   Finaliser – called when the OCaml value is GC‑collected.
   ------------------------------------------------------------------ */
static void caml_pcapng_finalize(value v)
{
    caml_pcapng_handle* h = (caml_pcapng_handle*)Data_custom_val(v);
    if (h->cap && !h->closed) {
        delete h->cap;
        h->closed = true;
    }
    delete h;   // free the wrapper itself
}

/* ------------------------------------------------------------------
   Custom operations descriptor.  The identifier string must be unique.
   ------------------------------------------------------------------ */
static struct custom_operations caml_pcapng_ops = {
    "pcapng.handle",
    caml_pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* ------------------------------------------------------------------
   Convert a libpcapng::Frame into an OCaml record of type [frame].
   The record layout must match the .mli definition exactly.
   ------------------------------------------------------------------ */
static value caml_frame_of_cpp(const Frame& frm)
{
    CAMLparam0();
    CAMLlocal3(ocaml_ts, ocaml_len, ocaml_data);
    CAMLlocal1(result);

    // timestamp – libpcapng gives us a 64‑bit integer (nanoseconds)
    ocaml_ts = caml_copy_int64(frm.timestamp());

    // length (int)
    ocaml_len = Val_int(frm.length());

    // data – copy exactly `length` bytes into an OCaml string
    const std::vector<uint8_t>& raw = frm.payload();
    ocaml_data = caml_alloc_string(frm.length());
    memcpy(String_val(ocaml_data), raw.data(), frm.length());

    // allocate the OCaml record (3 fields)
    result = caml_alloc(3, 0);        // tag 0 = record
    Store_field(result, 0, ocaml_ts);
    Store_field(result, 1, ocaml_len);
    Store_field(result, 2, ocaml_data);

    CAMLreturn(result);
}

/* ------------------------------------------------------------------
   OCaml entry points
   ------------------------------------------------------------------ */

/* open_file : string -> t */
extern "C" CAMLprim value caml_pcapng_open_file(value filename)
{
    CAMLparam1(filename);
    CAMLlocal1(block);

    const char* c_name = String_val(filename);
    try {
        // Construct the C++ object – this may throw std::runtime_error.
        Capture* cap = new Capture(std::string(c_name));

        // Allocate the custom block that holds the wrapper.
        block = caml_alloc_custom(&caml_pcapng_ops,
                                  sizeof(caml_pcapng_handle*),
                                  0,   // memory used by the block (0 = negligible)
                                  1);  // finaliser runs once

        caml_pcapng_handle* h = new caml_pcapng_handle();
        h->cap = cap;
        Data_custom_val(block) = (value)h;   // store pointer
        CAMLreturn(block);
    }
    catch (const std::exception& ex) {
        raise_error(ex.what());
    }
    CAMLreturn(Val_unit); // never reached
}

/* close : t -> unit */
extern "C" CAMLprim value caml_pcapng_close(value handle)
{
    CAMLparam1(handle);
    caml_pcapng_handle* h = (caml_pcapng_handle*)Data_custom_val(handle);
    if (h->cap && !h->closed) {
        delete h->cap;
        h->closed = true;
    }
    CAMLreturn(Val_unit);
}

/* next : t -> frame option */
extern "C" CAMLprim value caml_pcapng_next(value handle)
{
    CAMLparam1(handle);
    CAMLlocal1(res);
    caml_pcapng_handle* h = (caml_pcapng_handle*)Data_custom_val(handle);
    if (h->closed || h->cap == nullptr) raise_error("handle already closed");

    try {
        std::optional<Frame> maybe = h->cap->next();   // libpcapng API
        if (!maybe) {
            // None
            res = Val_int(0);   // 0 = None
        } else {
            // Some frame
            value ocaml_frame = caml_frame_of_cpp(*maybe);
            res = caml_alloc(1, 0);          // Some
            Store_field(res, 0, ocaml_frame);
        }
        CAMLreturn(res);
    }
    catch (const std::exception& ex) {
        raise_error(ex.what());
    }
}

/* iter : t -> (frame -> unit) -> unit */
extern "C" CAMLprim value caml_pcapng_iter(value handle, value callback)
{
    CAMLparam2(handle, callback);
    caml_pcapng_handle* h = (caml_pcapng_handle*)Data_custom_val(handle);
    if (h->closed || h->cap == nullptr) raise_error("handle already closed");

    // Iteration may be long; release the OCaml runtime lock while we walk.
    caml_release_runtime_system();

    try {
        while (true) {
            std::optional<Frame> maybe = h->cap->next();
            if (!maybe) break;          // end of file

            // Convert the frame and invoke the OCaml callback.
            // NOTE: we must reacquire the runtime before calling back.
            caml_acquire_runtime_system();
            value ocaml_frame = caml_frame_of_cpp(*maybe);
            value ret = caml_callback_exn(callback, ocaml_frame);
            caml_release_runtime_system();

            if (Is_exception_result(ret)) {
                // Propagate the OCaml exception to the caller.
                caml_acquire_runtime_system();
                caml_raise(ret);
            }
        }
    }
    catch (const std::exception& ex) {
        caml_acquire_runtime_system(); // make sure we are back in OCaml land
        raise_error(ex.what());
    }

    caml_acquire_runtime_system(); // final reacquire before returning
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------
   Register the exception name so that the C stub can raise it.
   This function is called from the OCaml side (see the .ml wrapper below).
   ------------------------------------------------------------------ */
extern "C" CAMLprim value caml_pcapng_register_exn(value exn)
{
    // Store the exception in the global table under the name "Pcapng_error".
    caml_register_named_value("Pcapng_error", exn);
    return Val_unit;
}
```

### What the stub does

| OCaml function | C++ implementation | Remarks |
|----------------|-------------------|---------|
| `open_file`    | `new Capture(filename)` | Throws `std::runtime_error` on failure → OCaml `Error`. |
| `close`        | `delete cap`      | Idempotent; also called by finaliser. |
| `next`         | `cap->next()` returns `std::optional<Frame>` | Returns `None` at EOF. |
| `iter`         | Loop calling `cap->next()` and `caml_callback_exn` | Releases the OCaml runtime lock while walking, but reacquires it for each callback (so callbacks can call back into OCaml).  Any exception raised by the callback aborts the loop and is re‑raised. |
| `register_exn`| registers the exception value for later use | Called once from the small OCaml wrapper (see below). |

