## 3. Tiny OCaml wrapper – **`pcapng.ml`**

Only a few lines are needed to expose the exception name to the C stub:

```ocaml
(*--------------------------------------------------------------------
   pcapng.ml – tiny glue for the C stub
  --------------------------------------------------------------------*)

exception Error of string

(* Register the exception so the C stub can raise it. *)
let () = 
  Callback.register_exception "Pcapng_error" (Error "")

(* External declarations – the names must match the C functions. *)
external open_file : string -> Pcapng.t = "caml_pcapng_open_file"
external close     : Pcapng.t -> unit = "caml_pcapng_close"
external next      : Pcapng.t -> Pcapng.frame option = "caml_pcapng_next"
external iter      : Pcapng.t -> (Pcapng.frame -> unit) -> unit = "caml_pcapng_iter"
external _register_exn : exn -> unit = "caml_pcapng_register_exn"
```

(If you are using `dune`, the `.ml` file can simply `include` the `.mli`.)

