## 4. Build instructions (Makefile excerpt)

```make
# --------------------------------------------------------------
# Minimal Makefile fragment for building the binding
# --------------------------------------------------------------

OCAMLFLAGS   = -thread -I $(OCAML_INC)
CXXFLAGS    = -std=c++11 -O2 -Wall -fPIC
LIBS        = -lpcapng   # <-- link with the real libpcapng library

# Paths – adjust to your environment
OCAML_INC   = $(shell ocamlc -where)

# Target
all: libpcapng_stubs.o libpcapng.a

# Build the C++ stub as a relocatable object
libpcapng_stubs.o: pcapng_stubs.cpp pcapng.mli
	$(CXX) $(CXXFLAGS) -c $< -o $@

# Archive it into a .a that dune/ocamlbuild can link with
libpcapng.a: libpcapng_stubs.o
	ar rcs $@ $^

# Clean
clean:
	rm -f *.o *.a
```

When using **`dune`**, the stub can be declared like:

```lisp
(library
 (name pcapng)
 (foreign_stubs
  (language cxx)
  (names pcapng_stubs))
 (libraries pcapng)               ; the real C++ lib
 (cflags (:standard -std=c++11))
 (ocamllex_flags (:standard))
)
```

